const crypto = require('crypto');

let binaryData = {};
let sourceFileName = 'upload.csv';

// Try webhook source first, then Google Drive
try {
  const webhookData = $('📥 Webhook — Receive CSV Upload').first();
  if (webhookData.binary && Object.keys(webhookData.binary).length > 0) {
    binaryData = webhookData.binary;
    const fileKey = Object.keys(binaryData)[0];
    sourceFileName = binaryData[fileKey].fileName || binaryData[fileKey].name || 'upload.csv';
  }
} catch(e) {}

try {
  const driveData = $('📥 Google Drive — Download CSV').first();
  if (driveData.binary && Object.keys(driveData.binary).length > 0) {
    binaryData = driveData.binary;
    const fileKey = Object.keys(binaryData)[0];
    sourceFileName = binaryData[fileKey].fileName || binaryData[fileKey].name || 'upload.csv';
  }
} catch(e) {}


let sourceHash = '';
let fileContent = '';

if (binaryData && Object.keys(binaryData).length > 0) {
  const fileKey = Object.keys(binaryData)[0];
  const file = binaryData[fileKey];
  sourceFileName = file.fileName || file.name || 'upload.csv';
  const buffer = Buffer.from(file.data, 'base64');
  fileContent = buffer.toString('utf8');
  sourceHash = crypto.createHash('sha256').update(fileContent).digest('hex');
}

let dryRun = false;
try {
  dryRun = $('⚙️ Config — Pipeline Settings').first().json.DRY_RUN;
} catch(e) {
  dryRun = false;
}

return [{
  json: { sourceFileName, sourceHash, dry_run: dryRun },
  binary: binaryData
}];

const sourceFileName = $('🔐 Hash File — SHA-256 + Extract').first().json.sourceFileName;
const sourceHash = $('🔐 Hash File — SHA-256 + Extract').first().json.sourceHash;
const dryRun = $('🔐 Hash File — SHA-256 + Extract').first().json.dry_run;

const VAT_RATE_DEFAULT = 15;

return $input.all().map((inputItem, idx) => {
  const row = inputItem.json;
  const rowNum = idx + 2;

  let amount_excl = parseFloat(row['amount_excl'] || row['amount_excl_vat'] || '0') || 0;
  let vat_rate = parseFloat(row['vat_rate'] || VAT_RATE_DEFAULT);
  let vat = parseFloat(row['vat'] || '0') || 0;
  let amount_incl = parseFloat(row['amount_incl'] || row['amount_incl_vat'] || '0') || 0;

  if ((!row['vat'] || row['vat'] === '') && vat_rate > 0) {
    vat = Math.round(amount_excl * vat_rate / 100 * 100) / 100;
  }
  if (!row['amount_incl'] && !row['amount_incl_vat']) {
    amount_incl = Math.round((amount_excl + vat) * 100) / 100;
  }

  return {
    json: {
      _rowNum: rowNum,
      sourceFileName,
      sourceHash,
      dry_run: dryRun,
      invoice_number: (row['invoice_number'] || '').toString().trim(),
      supplier_number: (row['supplier_number'] || '').toString().trim(),
      supplier_name: (row['supplier_name'] || '').toString().trim(),
      department: (row['department'] || '').toString().trim(),
      invoice_date: (row['invoice_date'] || '').toString().trim(),
      amount_excl_vat: Math.round(amount_excl * 100) / 100,
      vat: Math.round(vat * 100) / 100,
      amount_incl_vat: Math.round(amount_incl * 100) / 100,
      _vat_rate_used: vat_rate
    }
  };
});

const VAT_RATE_EXPECTED = 15;
const TOLERANCE = 0.01;

const results = [];

for (const inputItem of $input.all()) {
  const item = inputItem.json;
  const errors = [];
  const warnings = [];

  // RULE 1: Required fields
  const requiredFields = [
    { field: 'invoice_number',  label: 'Invoice Number' },
    { field: 'supplier_number', label: 'Supplier Number' },
    { field: 'supplier_name',   label: 'Supplier Name' },
    { field: 'department',      label: 'Department' },
    { field: 'invoice_date',    label: 'Invoice Date' },
  ];
  for (const { field, label } of requiredFields) {
    if (!item[field] || item[field].toString().trim() === '') {
      errors.push(`Missing required field: ${label}`);
    }
  }

  if (isNaN(item.amount_excl_vat)) errors.push('Missing or invalid: amount_excl_vat');
  if (isNaN(item.vat)) errors.push('Missing or invalid: vat');
  if (isNaN(item.amount_incl_vat)) errors.push('Missing or invalid: amount_incl_vat');

  // RULE 2: Math check
  if (!isNaN(item.amount_excl_vat) && !isNaN(item.vat) && !isNaN(item.amount_incl_vat)) {
    const expected = Math.round((item.amount_excl_vat + item.vat) * 100) / 100;
    const diff = Math.abs(item.amount_incl_vat - expected);
    if (diff > TOLERANCE) {
      errors.push(`Math check failed: ${item.amount_incl_vat} ≠ ${item.amount_excl_vat} + ${item.vat} = ${expected}`);
    }
  }

  // RULE 3: VAT rate check
  if (!isNaN(item.amount_excl_vat) && !isNaN(item.vat) && item.amount_excl_vat > 0) {
    const derivedRate = Math.round((item.vat / item.amount_excl_vat) * 100 * 100) / 100;
    if (Math.abs(derivedRate - VAT_RATE_EXPECTED) > 0.1) {
      warnings.push(`VAT rate mismatch: derived ${derivedRate}%, expected ${VAT_RATE_EXPECTED}%`);
    }
  }

  // RULE 4: Invoice date not in future
  if (item.invoice_date && item.invoice_date.trim() !== '') {
    const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
    if (!dateRegex.test(item.invoice_date.trim())) {
      errors.push(`Invalid date format: "${item.invoice_date}". Expected YYYY-MM-DD`);
    } else {
      const nowJHB = new Date(new Date().getTime() + 2 * 60 * 60 * 1000);
      const todayJHB = nowJHB.toISOString().split('T')[0];
      if (item.invoice_date.trim() > todayJHB) {
        errors.push(`Invoice date is in the future: ${item.invoice_date} (today JHB: ${todayJHB})`);
      }
    }
  }

  // RULE 5: No negative amounts
  if (!isNaN(item.amount_excl_vat) && item.amount_excl_vat < 0) errors.push('amount_excl_vat cannot be negative');
  if (!isNaN(item.vat) && item.vat < 0) errors.push('vat cannot be negative');
  if (!isNaN(item.amount_incl_vat) && item.amount_incl_vat < 0) errors.push('amount_incl_vat cannot be negative');

  const isValid = errors.length === 0;
  const allNotes = [
    ...errors.map(e => `ERROR: ${e}`),
    ...warnings.map(w => `WARNING: ${w}`)
  ].join(' | ');

  console.log(`[Validate] Row ${item._rowNum} (${item.invoice_number}): ${isValid ? 'VALID' : 'INVALID'}`);

  results.push({
    json: {
      ...item,
      valid: isValid,
      validation_notes: allNotes || null,
      _errorCount: errors.length,
      _warningCount: warnings.length
    }
  });
}

return results;

