const allValidated = $('🔍 Validate Row — Business Rules').all() || [];
const allDedup = $input.all() || [];

const seenInBatch = new Set();

return allValidated.map((validatedItem, i) => {
  const validated = validatedItem.json;
  const dbResult = allDedup[i]?.json;

  // Check if already exists in DB
  const existsInDB = !!(dbResult && dbResult.is_duplicate === true);

  // Check if already seen in this batch
  const batchKey = `${validated.supplier_number}|${validated.invoice_number}`;
  const existsInBatch = seenInBatch.has(batchKey);

  const isDuplicate = existsInDB || existsInBatch;

  // Only add to seen set if not already a duplicate
  if (!isDuplicate) seenInBatch.add(batchKey);

  return {
    json: {
      ...validated,
      is_duplicate: isDuplicate,
      status: isDuplicate ? 'duplicate' : 'pending_insert',
      validation_notes: isDuplicate
        ? `Duplicate: (${validated.supplier_number}, ${validated.invoice_number}) already exists`
        : validated.validation_notes
    }
  };
});

// ============================================================
// NODE: Mark Duplicate — Collect for Metrics
// PURPOSE: Formats duplicate rows for the metrics aggregator.
// ============================================================

const item = $input.item.json;

console.log(`[Duplicate] Skipping insert for: ${item.invoice_number} / ${item.supplier_number}`);

return [{
  json: {
    invoice_number:  item.invoice_number,
    supplier_number: item.supplier_number,
    supplier_name:   item.supplier_name,
    status:          'duplicate',
    reason:          item.validation_notes || `Duplicate key: (${item.supplier_number}, ${item.invoice_number})`,
    sourceFileName:  item.sourceFileName
  }
}];

// Only trigger email once — skip if triggered by duplicate collector when inserts also exist
const fromDuplicate = $input.first().json.status === 'duplicate';
const hasInserts = (() => { try { return $('💾 Insert — supplier_invoices').all().length > 0; } catch(e) { return false; } })();
const hasDryInserts = (() => { try { return $('💾 Insert — supplier_invoices_staging').all().length > 0; } catch(e) { return false; } })();

if (fromDuplicate && (hasInserts || hasDryInserts)) {
  return [];
}

let allItems = [];
try {
  allItems = $('🏷️ Tag — Duplicate or New').all() || [];
} catch(e) {
  allItems = [];
}

let failedItems = [];
try {
  failedItems = $('💾 Insert — supplier_invoices_failures').all() || [];
} catch(e) {
  failedItems = [];
}

const totalProcessed = allItems.length;
const insertedCount = allItems.filter(i => i.json.status === 'pending_insert').length;
const duplicateCount = allItems.filter(i => i.json.status === 'duplicate').length;
const failedCount = failedItems.length;

const issueRows = [];
for (const item of allItems.filter(i => i.json.status === 'duplicate')) {
  issueRows.push({
    invoice_number: item.json.invoice_number || 'N/A',
    supplier_number: item.json.supplier_number || 'N/A',
    supplier_name: item.json.supplier_name || 'N/A',
    status: 'duplicate',
    reason: item.json.validation_notes || 'Duplicate key'
  });
}

for (const item of failedItems) {
  issueRows.push({
    invoice_number: item.json.invoice_number || 'N/A',
    supplier_number: item.json.supplier_number || 'N/A',
    supplier_name: item.json.supplier_name || 'N/A',
    status: 'failed',
    reason: item.json.validation_notes || 'Validation failed'
  });
}

const sourceFileName = allItems[0]?.json?.sourceFileName || 'Unknown';
const ingestTime = new Date(new Date().getTime() + 2 * 60 * 60 * 1000)
  .toISOString().replace('T', ' ').substring(0, 19) + ' SAST';

return [{
  json: {
    totalProcessed,
    insertedCount,
    duplicateCount,
    failedCount,
    issueRows: issueRows.slice(0, 20),
    sourceFileName,
    ingestTime,
    hasIssues: issueRows.length > 0
  }
}];

const item = $input.first();
const binaryData = item.binary || {};

const normalizedBinary = {};
if (Object.keys(binaryData).length > 0) {
  const firstKey = Object.keys(binaryData)[0];
  normalizedBinary.file = binaryData[firstKey];
}

return [{
  json: item.json,
  binary: normalizedBinary
}];
